import argparse
import json
import os
import numpy as np
import heapq
from collections import deque
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n["coords"])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                if w > 0:
                    adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        if w > 0:
            adj[r_idx].append((j, w))
            adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class GreedyPlanner:
    def __init__(self, dist_denom=3.6, reverse_penalty=0.3,
                 visited_penalty=0.1, persist_boost=1.05):
        self.dist_denom = dist_denom
        self.reverse_penalty = reverse_penalty
        self.visited_penalty = visited_penalty
        self.persist_boost = persist_boost
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_pos = None
        self.last_target_j = None
        self.history = deque(maxlen=30)

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=float)
        nodes = obs["nodes"]
        neighbors = obs["neighbors"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                node_to_nb[j] = idx

        first_step = {}
        for j in range(N):
            if dist[j] == float('inf') or prev[j] is None:
                continue
            cur = j
            depth = 0
            while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                cur = prev[cur]
                depth += 1
            if prev[cur] == r_idx and cur in node_to_nb:
                first_step[j] = node_to_nb[cur]

        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        best_score = -float('inf')
        best_j = None

        for j in range(N):
            if j not in first_step:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue
            d = dist[j]
            score = utility / (d + self.dist_denom)
            if first_step[j] == reverse_idx:
                score *= self.reverse_penalty
            if nodes[j].get("visited", False):
                score *= (1.0 - self.visited_penalty)
            if j == self.last_target_j:
                score *= self.persist_boost
            if score > best_score:
                best_score = score
                best_j = j

        if best_j is not None:
            self.last_target_j = best_j
            return neighbors[first_step[best_j]]

        # Fallback 1: move toward nearest frontier
        if frontiers and neighbors:
            frontiers_arr = np.array(frontiers, dtype=float)
            best_f_score = float('inf')
            best_f_idx = None
            for idx, nb in enumerate(neighbors):
                diffs = frontiers_arr - np.array(nb, dtype=float)
                f_dists = np.linalg.norm(diffs, axis=1)
                min_f_dist = float(np.min(f_dists))
                score = min_f_dist
                if idx == reverse_idx:
                    score /= max(self.reverse_penalty, 0.01)
                if score < best_f_score:
                    best_f_score = score
                    best_f_idx = idx
            if best_f_idx is not None:
                self.last_target_j = None
                return neighbors[best_f_idx]

        # Fallback 2: nearest unvisited node
        best_u_score = float('inf')
        best_u_idx = None
        for j in range(N):
            if j not in first_step:
                continue
            if nodes[j].get("visited", False):
                continue
            d = dist[j]
            if first_step[j] == reverse_idx:
                d /= max(self.reverse_penalty, 0.01)
            if d < best_u_score:
                best_u_score = d
                best_u_idx = first_step[j]
        if best_u_idx is not None:
            self.last_target_j = None
            return neighbors[best_u_idx]

        # Ultimate fallback: avoid reverse and recent history
        candidates = list(range(len(neighbors)))
        if reverse_idx is not None and len(candidates) > 1:
            candidates = [c for c in candidates if c != reverse_idx]
        best_hist_score = float('inf')
        best_hist_idx = None
        for idx in candidates:
            pos = tuple(np.round(neighbors[idx], 6))
            try:
                h = list(self.history).index(pos)
                score = h
            except ValueError:
                score = -1
            if score < best_hist_score:
                best_hist_score = score
                best_hist_idx = idx
        if best_hist_idx is not None:
            self.last_target_j = None
            return neighbors[best_hist_idx]
        self.last_target_j = None
        return neighbors[0] if neighbors else None

    def update_state(self, action, obs):
        self.prev_pos = np.array(obs["robot_pos"], dtype=float)
        if action is not None:
            self.history.append(tuple(np.round(action, 6)))


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for step in range(128):
        action = planner.plan(obs)
        if action is None:
            break
        obs, info = env.step(action)
        planner.update_state(action, obs)
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        import torch
        _ = torch.load(ckpt_path, map_location="cpu")

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, "r") as f:
            eval_config = json.load(f)
        if "episodes" in eval_config and isinstance(eval_config["episodes"], list):
            episodes = eval_config["episodes"]

    if not episodes:
        maps_dir = os.path.join(args.data_path, "maps_eval")
        for env_type in ["room", "tunnel", "outdoor"]:
            type_dir = os.path.join(maps_dir, env_type)
            if not os.path.isdir(type_dir):
                continue
            for fname in sorted(os.listdir(type_dir)):
                if fname.endswith(".png"):
                    episodes.append({
                        "map_path": os.path.join("maps_eval", env_type, fname),
                        "env_type": env_type
                    })

    # Default config (overridden via checkpoint config if present)
    cfg = {"dist_denom": 3.6, "reverse_penalty": 0.3,
           "visited_penalty": 0.1, "persist_boost": 1.05}
    cfg_path = os.path.join(args.checkpoint, "planner_cfg.json")
    if os.path.exists(cfg_path):
        with open(cfg_path, "r") as f:
            cfg.update(json.load(f))

    planner = GreedyPlanner(**cfg)

    results = []
    per_type = {"room": [], "tunnel": [], "outdoor": []}

    for ep in episodes:
        map_path = os.path.join(args.data_path, ep["map_path"])
        env_type = ep.get("env_type", "unknown")
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get("success", False) else 0
        distance = float(metrics.get("travel_distance", 0.0))
        explored = float(metrics.get("explored_rate", 0.0))
        results.append({
            "map_path": ep["map_path"],
            "env_type": env_type,
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })
        if env_type in per_type:
            per_type[env_type].append(results[-1])

    total = len(results)
    explored_rate = sum(r["explored_rate"] for r in results) / total if total else 0.0
    success_rate = sum(r["success"] for r in results) / total if total else 0.0
    dists = [r["travel_distance"] for r in results if r["success"]]
    travel_distance = sum(dists) / len(dists) if dists else 0.0

    per_type_stats = {}
    for etype, eps in per_type.items():
        if not eps:
            continue
        srate = sum(e["success"] for e in eps) / len(eps)
        erate = sum(e["explored_rate"] for e in eps) / len(eps)
        dts = [e["travel_distance"] for e in eps if e["success"]]
        tdist = sum(dts) / len(dts) if dts else 0.0
        per_type_stats[etype] = {
            "explored_rate": erate,
            "travel_distance": tdist,
            "success_rate": srate
        }

    output = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": results,
        "per_type": per_type_stats,
        "total_episodes": total
    }

    out_dir = os.path.dirname(args.output)
    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(output, f, indent=2)
    print(f"Evaluated {total} episodes. explored={explored_rate:.4f} succ={success_rate:.4f} dist={travel_distance:.1f}")


if __name__ == "__main__":
    main()
